            {
                node.Children[ch] = new TrieNode();
            }
            node = node.Children[ch];
        }
        node.IsEnd = true;
    }

    private static bool Search(TrieNode root, int key)
    {
        TrieNode node = root;
        foreach (char ch in key.ToString())
        {
            if (!node.Children.ContainsKey(ch))
            {
                return false;
            }
            node = node.Children[ch];
        }
        return node.IsEnd;
    }

    public static int InsertSearch(int[] arr)
    {
