        int mid = n / 2;
        TrieNode root = new TrieNode();

        for (int i = 0; i < mid; i++)
        {
            Insert(root, arr[i]);
        }

        int count = 0;
        for (int i = mid; i < n; i++)
        {
            if (Search(root, arr[i]))
